:root {
  --crimson: #C2095A;
  --crimson-light: #E0106A;
  --crimson-dim: rgba(194, 9, 90, 0.15);
  --crimson-glow: rgba(194, 9, 90, 0.35);
  --bg-primary: #0C0B0F;
  --bg-secondary: #111018;
  --bg-card: #15141C;
  --bg-card-hover: #1C1B26;
  --border: rgba(255,255,255,0.07);
  --border-crimson: rgba(194,9,90,0.3);
  --text-white: #F5F4F8;
  --text-muted: #7A7890;
  --text-subtle: #4A4860;
  --divider: rgba(255,255,255,0.05);
  --font-display: 'Instrument Serif', Georgia, serif;
  --font-italic: 'Instrument Serif', Georgia, serif;
  --font-body: 'DM Sans', sans-serif;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

.revory-landing-page-root { scroll-behavior: smooth; }

.revory-landing-page {
  background-color: var(--bg-primary);
  color: var(--text-white);
  font-family: var(--font-body);
  font-weight: 400;
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

/* ——— NAV ——— */
.revory-landing-page nav {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 100;
  padding: 0 2rem;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: rgba(12,11,15,0.85);
  backdrop-filter: blur(16px);
  border-bottom: 1px solid var(--border);
}

.logo {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  text-decoration: none;
}
.logo-icon {
  height: 52px;
  width: auto;
  flex-shrink: 0;
  display: flex;
  align-items: center;
}
.logo-icon img {
  height: 52px;
  width: auto;
  display: block;
}
.logo-wordmark {
  font-family: 'Instrument Serif', Georgia, serif;
  font-size: 1.2rem;
  font-weight: 400;
  letter-spacing: 0.14em;
  color: var(--text-white);
  text-transform: uppercase;
  line-height: 1;
}

.nav-links {
  display: flex;
  gap: 2rem;
  list-style: none;
}
.nav-links a {
  color: var(--text-muted);
  text-decoration: none;
  font-size: 0.875rem;
  font-weight: 500;
  transition: color 0.2s;
}
.nav-links a:hover { color: var(--text-white); }

.nav-cta {
  background: var(--crimson);
  color: white !important;
  padding: 0.5rem 1.25rem;
  border-radius: 6px;
  font-weight: 600 !important;
  transition: background 0.2s !important;
}
.nav-cta:hover { background: var(--crimson-light) !important; color: white !important; }

